import hashlib

def encrypt_sensitive_data(data: str) -> str:
    """
    Encrypts sensitive user data before storing it in the database.

    Args:
        data: The sensitive user data to encrypt.

    Returns:
        The encrypted data.
    """

    # Use the SHA-256 hashing algorithm to encrypt the data.
